import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ChannelType {
  PHONE = 'Phone',
  LINE = 'LINE',
  EMAIL = 'Email'
}

export enum InquiryStatus {
  NEW = '新規',
  IN_PROGRESS = '対応中',
  DONE = '完了'
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  carModel?: string;
}

export interface Inquiry {
  id: string;
  customerId: string;
  customerName: string; // Denormalized for display
  channel: ChannelType;
  subject: string;
  lastMessage: string;
  timestamp: string;
  status: InquiryStatus;
  assignedTo?: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export enum ImageSize {
  SIZE_1K = '1K',
  SIZE_2K = '2K',
  SIZE_4K = '4K'
}

import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { ImageSize } from '../types';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

// 1. AI Powered Chatbot using gemini-3-pro-preview
export const createChatSession = (): Chat => {
  const ai = getAiClient();
  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: "You are a helpful assistant for 'Ishigami Vehicle' staff. You help draft responses to customers, summarize inquiries, and provide advice on vehicle buyouts. Be professional, polite, and concise in Japanese.",
    },
  });
};

export const sendMessageStream = async (chat: Chat, message: string) => {
  return chat.sendMessageStream({ message });
};

// 2. Image Generation using gemini-3-pro-image-preview (Nano Banana Pro)
export const generateMarketingImage = async (prompt: string, size: ImageSize): Promise<string | null> => {
  const ai = getAiClient();

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9", // Good for web banners
          imageSize: size
        }
      }
    });

    // Extract image
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const base64EncodeString = part.inlineData.data;
          return `data:image/png;base64,${base64EncodeString}`;
        }
      }
    }
    return null;
  } catch (error) {
    console.error("Image generation failed:", error);
    throw error;
  }
};

