import React, { useState, useEffect, useRef } from 'react';
import { createChatSession, sendMessageStream } from '../services/geminiService';
import { ChatMessage } from '../types';
import { Chat, GenerateContentResponse } from "@google/genai";
import ReactMarkdown from 'react-markdown';

const AiChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize chat session on mount
    try {
      chatSessionRef.current = createChatSession();
      setMessages([{
        role: 'model',
        text: 'こんにちは！石神車両のアシスタントAIです。お客様への返信案作成や、業務に関する質問があればお気軽にどうぞ。',
        timestamp: new Date()
      }]);
    } catch (e) {
      console.error("Failed to initialize chat", e);
      setMessages([{
        role: 'model',
        text: '現在AIサービスに接続できません。APIキーを確認してください。',
        timestamp: new Date()
      }]);
    }
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || !chatSessionRef.current || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const streamResult = await sendMessageStream(chatSessionRef.current, userMsg.text);

      let fullResponse = '';
      setMessages(prev => [...prev, { role: 'model', text: '', timestamp: new Date() }]);

      for await (const chunk of streamResult) {
         const responseChunk = chunk as GenerateContentResponse;
         const text = responseChunk.text || '';
         fullResponse += text;

         setMessages(prev => {
            const newHistory = [...prev];
            const lastMsg = newHistory[newHistory.length - 1];
            if (lastMsg.role === 'model') {
                lastMsg.text = fullResponse;
            }
            return newHistory;
         });
      }

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: 'エラーが発生しました。もう一度お試しください。', timestamp: new Date() }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] bg-white rounded-xl shadow-lg border border-slate-200 overflow-hidden">
      {/* Header */}
      <div className="bg-gradient-to-r from-brand-700 to-brand-600 p-4 flex items-center shadow-md">
        <div className="p-2 bg-white/20 rounded-full">
            <span className="material-icons-outlined text-white">smart_toy</span>
        </div>
        <div className="ml-3">
            <h2 className="text-lg font-bold text-white">AI業務アシスタント</h2>
            <p className="text-xs text-brand-100">Powered by Gemini 3 Pro</p>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[80%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 mt-1 shadow-sm
                ${msg.role === 'user' ? 'bg-slate-800 ml-3' : 'bg-brand-600 mr-3'}`}>
                <span className="material-icons-outlined text-white text-sm">
                  {msg.role === 'user' ? 'person' : 'smart_toy'}
                </span>
              </div>
              <div className={`p-4 rounded-2xl shadow-sm text-sm leading-relaxed prose prose-sm max-w-none
                ${msg.role === 'user' 
                  ? 'bg-white text-slate-800 rounded-tr-none border border-slate-100' 
                  : 'bg-white text-slate-800 rounded-tl-none border border-brand-100'}`}>
                <ReactMarkdown>{msg.text}</ReactMarkdown>
                {msg.text === '' && isLoading && idx === messages.length -1 && (
                    <span className="inline-flex gap-1 items-center">
                        <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce"></span>
                        <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce delay-100"></span>
                        <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce delay-200"></span>
                    </span>
                )}
              </div>
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-200">
        <div className="relative flex items-end border border-slate-300 rounded-xl shadow-sm focus-within:ring-2 focus-within:ring-brand-500 focus-within:border-transparent transition-all bg-white overflow-hidden">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="ここにメッセージを入力（例：お客様への返信案を作成して）"
            className="w-full max-h-32 p-4 text-slate-800 placeholder-slate-400 focus:outline-none resize-none bg-transparent"
            rows={1}
            style={{ minHeight: '60px' }}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className={`m-2 p-2 rounded-lg flex items-center justify-center transition-colors
              ${!input.trim() || isLoading 
                ? 'bg-slate-100 text-slate-300 cursor-not-allowed' 
                : 'bg-brand-600 text-white hover:bg-brand-700 shadow-md'}`}
          >
            <span className="material-icons-outlined">send</span>
          </button>
        </div>
        <p className="text-center text-xs text-slate-400 mt-2">
            AIは間違いを犯す可能性があります。回答を確認してから使用してください。
        </p>
      </div>
    </div>
  );
};

export default AiChat;

import React, { useState } from 'react';
import { generateMarketingImage } from '../services/geminiService';
import { ImageSize } from '../types';

const MarketingGen: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [size, setSize] = useState<ImageSize>(ImageSize.SIZE_1K);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    setError(null);
    setGeneratedImage(null);

    try {
      const imageBase64 = await generateMarketingImage(prompt, size);
      if (imageBase64) {
        setGeneratedImage(imageBase64);
      } else {
        setError("画像の生成に失敗しました。プロンプトを変更して再試行してください。");
      }
    } catch (err) {
      setError("AIサービスへの接続中にエラーが発生しました。");
      console.error(err);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex items-center gap-3 mb-6">
             <div className="p-3 bg-purple-100 rounded-lg text-purple-600">
                <span className="material-icons-outlined">collections</span>
             </div>
             <div>
                <h2 className="text-xl font-bold text-slate-800">マーケティング画像生成</h2>
                <p className="text-sm text-slate-500">キャンペーンやSNS用の画像をAIが作成します (Nano Banana Pro)</p>
             </div>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">
              画像の説明 (プロンプト)
            </label>
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="例：未来的な電気自動車が都市の道路を走っている、サイバーパンク風、高画質、夕暮れ"
              className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-brand-500 min-h-[100px]"
            />
          </div>

          <div>
             <label className="block text-sm font-medium text-slate-700 mb-2">
              解像度
            </label>
            <div className="flex gap-3">
              {[ImageSize.SIZE_1K, ImageSize.SIZE_2K, ImageSize.SIZE_4K].map((s) => (
                <button
                  key={s}
                  onClick={() => setSize(s)}
                  className={`flex-1 py-2 px-4 rounded-lg border text-sm font-semibold transition-all ${
                    size === s
                      ? 'bg-purple-600 text-white border-purple-600 shadow-md'
                      : 'bg-white text-slate-600 border-slate-300 hover:border-purple-300 hover:bg-purple-50'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          <div className="pt-4">
            <button
              onClick={handleGenerate}
              disabled={isGenerating || !prompt}
              className={`w-full py-3 px-4 rounded-lg font-bold text-white flex items-center justify-center gap-2 transition-all
                ${isGenerating || !prompt
                  ? 'bg-slate-300 cursor-not-allowed'
                  : 'bg-purple-600 hover:bg-purple-700 shadow-lg hover:shadow-xl'
                }`}
            >
              {isGenerating ? (
                <>
                  <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                  生成中... (Nano Banana Pro)
                </>
              ) : (
                <>
                  <span className="material-icons-outlined">auto_awesome</span>
                  画像を生成する
                </>
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Result Area */}
      {error && (
        <div className="bg-red-50 text-red-600 p-4 rounded-lg border border-red-200 flex items-center gap-2">
          <span className="material-icons-outlined">error_outline</span>
          {error}
        </div>
      )}

      {generatedImage && (
        <div className="bg-white p-6 rounded-xl shadow-lg border border-slate-200 animate-fade-in">
          <h3 className="text-lg font-bold text-slate-800 mb-4 flex justify-between items-center">
             生成結果
             <a 
               href={generatedImage} 
               download={`ishigami-generated-${Date.now()}.png`}
               className="text-sm text-brand-600 hover:text-brand-800 font-medium flex items-center gap-1"
             >
               <span className="material-icons-outlined text-sm">download</span>
               ダウンロード
             </a>
          </h3>
          <div className="relative rounded-lg overflow-hidden border border-slate-100 bg-slate-50">
             <img src={generatedImage} alt="Generated marketing asset" className="w-full h-auto object-cover" />
          </div>
        </div>
      )}

      {!generatedImage && !isGenerating && !error && (
        <div className="text-center py-12 text-slate-400 bg-slate-50 rounded-xl border-2 border-dashed border-slate-200">
           <span className="material-icons-outlined text-4xl mb-2 opacity-50">image</span>
           <p>ここに生成された画像が表示されます</p>
        </div>
      )}
    </div>
  );
};

export default MarketingGen;

