const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

// 1. AI Powered Chatbot using gemini-3-pro-preview
export const createChatSession = (): Chat => {
  const ai = getAiClient();
  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: "You are a helpful assistant for 'Ishigami Vehicle' staff. You help draft responses to customers, summarize inquiries, and provide advice on vehicle buyouts. Be professional, polite, and concise in Japanese.",
    },
  });
};

export const sendMessageStream = async (chat: Chat, message: string) => {
  return chat.sendMessageStream({ message });
};

// 2. AI Text Refinement for Customer Communication
export const refineMessage = async (draft: string, type: 'SMS' | 'EMAIL'): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    あなたは自動車販売買取店「石上車両」のスタッフです。
    以下の「下書き」をもとに、お客様へ送るメッセージを清書してください。

    条件:
    - 送信手段: ${type}
    - ${type === 'SMS' ? 'SMSなので、簡潔に、短めの文章にしてください（1通に収まる程度）。' : 'メールなので、件名は含めず、ビジネスとして丁寧な挨拶と本文を作成してください。'}
    - 丁寧語を使用してください。
    - プレースホルダー（[お客様名]など）は使わず、文脈から判断できる内容は自然に補完してください。

    下書き:
    ${draft}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || draft;
  } catch (e) {
    console.error("Text refinement failed", e);
    return draft;
  }
};

export const generateMarketingImage = async (prompt: string, size: ImageSize): Promise<string | null> => {
  const ai = getAiClient();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: size
        }
      }
    });

    if (response.candidates && response.candidates[0].content && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const base64EncodeString = part.inlineData.data;
          // Return as data URL
          return `data:${part.inlineData.mimeType};base64,${base64EncodeString}`;
        }
      }
    }
    return null;
  } catch (e) {
    console.error("Image generation failed", e);
    return null;
  }
};

