import React, { useState } from 'react';
import { Inquiry } from '../types';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface SlipPreviewModalProps {
  isOpen: boolean;
  onClose: () => void;
  data: Inquiry;
}

const SlipPreviewModal: React.FC<SlipPreviewModalProps> = ({ isOpen, onClose, data }) => {
  const [isGenerating, setIsGenerating] = useState(false);

  if (!isOpen) return null;

  const handleDownloadPdf = async () => {
    const input = document.getElementById('slip-print-area');
    if (!input) return;

    setIsGenerating(true);
    try {
      // 1. Capture the printable area as a high-res image
      const canvas = await html2canvas(input, { scale: 2, useCORS: true });
      const imgData = canvas.toDataURL('image/png');

      // 2. Generate PDF
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * pdfWidth) / imgProps.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, imgHeight);
      pdf.save(`ishigami_slip_${data.id}_${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (error) {
      console.error('PDF generation failed', error);
      alert('PDFの作成に失敗しました。');
    } finally {
      setIsGenerating(false);
    }
  };

  // Common cell styles for the "Excel" look
  const cellLabel = "bg-slate-100 font-bold text-center border border-slate-400 p-2 text-xs flex items-center justify-center";
  const cellValue = "bg-white border border-slate-400 p-2 text-sm font-medium flex items-center";

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 overflow-y-auto">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl flex flex-col max-h-[90vh]">

        {/* Header Actions */}
        <div className="flex justify-between items-center p-4 border-b border-slate-200 bg-slate-50 rounded-t-xl">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <span className="material-icons-outlined text-brand-600">print</span>
            伝票プレビュー
          </h2>
          <div className="flex gap-3">
            <button 
              onClick={onClose}
              className="px-4 py-2 text-sm font-bold text-slate-500 hover:bg-slate-200 rounded-lg transition-colors"
            >
              閉じる
            </button>
            <button 
              onClick={handleDownloadPdf}
              disabled={isGenerating}
              className="px-6 py-2 text-sm font-bold text-white bg-brand-600 hover:bg-brand-700 rounded-lg shadow-md flex items-center gap-2 transition-colors disabled:opacity-50"
            >
              {isGenerating ? (
                <>
                  <span className="material-icons-outlined animate-spin text-sm">refresh</span>
                  生成中...
                </>
              ) : (
                <>
                  <span className="material-icons-outlined text-sm">picture_as_pdf</span>
                  PDFダウンロード
                </>
              )}
            </button>
          </div>
        </div>

        {/* Scrollable Preview Area */}
        <div className="flex-1 overflow-auto p-8 bg-slate-500/10 flex justify-center">
          {/* A4 Paper Aspect Ratio Container */}
          <div 
            id="slip-print-area" 
            className="bg-white p-12 shadow-lg w-[210mm] min-h-[297mm] text-slate-900 box-border origin-top transform scale-100"
          >
            {/* Slip Header */}
            <div className="flex justify-between items-end mb-8 border-b-2 border-slate-800 pb-4">
               <div>
                  <h1 className="text-3xl font-serif font-black tracking-widest mb-2">車輛管理伝票</h1>
                  <p className="text-sm text-slate-500">No. {data.slip?.stockNumber || 'TBD'} / Date: {new Date().toLocaleDateString()}</p>
               </div>
               <div className="text-right">
                  <h3 className="text-xl font-bold text-brand-700">石上車両 株式会社</h3>
                  <p className="text-xs text-slate-500 mt-1">〒000-0000 北海道札幌市...</p>
                  <p className="text-xs text-slate-500">TEL: 011-000-0000 / FAX: 011-000-0000</p>
               </div>
            </div>

            {/* Main Grid Layout (Simulating Excel) */}
