import React, { useState } from 'react';
import { Inquiry } from '../types';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface SlipPreviewModalProps {
  isOpen: boolean;
  onClose: () => void;
  data: Inquiry;
  onUpdate: (updatedData: Inquiry) => void;
}

const SlipPreviewModal: React.FC<SlipPreviewModalProps> = ({ isOpen, onClose, data, onUpdate }) => {
  const [isGenerating, setIsGenerating] = useState(false);

  if (!isOpen) return null;

  const handleDownloadPdf = async () => {
    const input = document.getElementById('slip-print-area');
    if (!input) return;

    setIsGenerating(true);
    try {
      // 1. Capture the printable area
      const canvas = await html2canvas(input, { 
        scale: 2, 
        useCORS: true,
        // Ensure inputs are captured correctly
        onclone: (document) => {
            const inputs = document.querySelectorAll('input, textarea');
            inputs.forEach((input: any) => {
                input.style.border = 'none'; // Ensure no extra borders in PDF
            });
        }
      });
      const imgData = canvas.toDataURL('image/png');

      // 2. Generate PDF
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * pdfWidth) / imgProps.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, imgHeight);
      pdf.save(`ishigami_slip_${data.id}_${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (error) {
      console.error('PDF generation failed', error);
      alert('PDFの作成に失敗しました。');
    } finally {
      setIsGenerating(false);
    }
  };

  // Helper to update nested state safely
  const updateField = (section: 'customer' | 'vehicle' | 'slip', field: string, value: any) => {
    const newData = { ...data };
    // Ensure the section exists
    if (!newData[section]) {
        (newData as any)[section] = {};
    }
    (newData as any)[section] = {
        ...(newData as any)[section],
        [field]: value
    };
    onUpdate(newData);
  };

  // Common cell styles
  const cellLabel = "bg-slate-100 font-bold text-center border border-slate-600 p-2 text-xs flex items-center justify-center select-none";
  const cellValue = "bg-white border border-slate-600 p-0 text-sm font-medium relative"; // Removed padding for input fit
  const inputStyle = "w-full h-full px-2 py-1 bg-transparent border-none outline-none focus:bg-blue-50 focus:ring-2 focus:ring-inset focus:ring-blue-500 transition-colors text-slate-900";

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 overflow-y-auto">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl flex flex-col max-h-[95vh]">

