          <div>
            <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <span className="material-icons-outlined text-brand-600">edit_note</span>
                伝票編集・プレビュー
            </h2>
            <p className="text-xs text-slate-500 mt-1">ここでの変更は自動的に保存されます</p>
          </div>
          <div className="flex gap-3">
            <button 
              onClick={onClose}
              className="px-4 py-2 text-sm font-bold text-slate-500 hover:bg-slate-200 rounded-lg transition-colors"
            >
              閉じる
            </button>
            <button 
              onClick={handleDownloadPdf}
              disabled={isGenerating}
              className="px-6 py-2 text-sm font-bold text-white bg-brand-600 hover:bg-brand-700 rounded-lg shadow-md flex items-center gap-2 transition-colors disabled:opacity-50"
            >
              {isGenerating ? (
