                      <span className="material-icons-outlined text-sm mr-2 align-middle">sms</span> SMS
                  </button>
                  <button 
                      onClick={() => setMessageType('EMAIL')}
                      className={`flex-1 py-2 rounded-lg font-bold text-sm transition-colors border-2 ${messageType === 'EMAIL' ? 'border-orange-500 bg-orange-50 text-orange-700' : 'border-slate-100 bg-white text-slate-500 hover:border-slate-300'}`}
                  >
                      <span className="material-icons-outlined text-sm mr-2 align-middle">mail</span> Email
                  </button>
              </div>

              <div className="relative">
                  <textarea 
                      value={draftMessage}
                      onChange={(e) => setDraftMessage(e.target.value)}
