                              <label key={opt} className="inline-flex items-center cursor-pointer">
                                  <input 
                                      type="radio" 
                                      name="plateStatus"
                                      checked={formData.vehicle?.plateStatus === opt}
                                      onChange={() => updateVehicle('plateStatus', opt)}
                                      className="form-radio h-4 w-4 text-brand-600 border-slate-300 focus:ring-brand-500" 
                                  />
                                  <span className="ml-2 text-sm text-slate-700">{opt}</span>
                              </label>
