                      </div>
                  </div>
                  <div className="md:col-span-8">
                      <label className="block text-xs font-bold text-slate-500 mb-1">登録番号</label>
                      <input 
                          type="text" 
                          value={formData.vehicle?.registrationNumber || ''} 
                          onChange={(e) => updateVehicle('registrationNumber', e.target.value)}
                          className="w-full border-slate-300 rounded-md shadow-sm focus:border-brand-500 focus:ring-brand-500" 
                      />
                  </div>
              </div>

              {/* 6. Vehicle Condition */}
              <div>
                  <label className="block text-xs font-bold text-slate-500 mb-1">車輛状態</label>
                  <textarea 
                      rows={5}
                      value={formData.vehicle?.conditionNotes || formData.content || ''} 
                      onChange={(e) => updateVehicle('conditionNotes', e.target.value)}
                      className="w-full border-slate-300 rounded-md shadow-sm focus:border-brand-500 focus:ring-brand-500 resize-none p-4 leading-relaxed"
                  />
              </div>
          </div>

          {/* Footer Actions */}
          <div className="bg-slate-50 px-8 py-6 border-t border-slate-200 flex justify-end">
              <button 
                  onClick={handleSave}
                  className="bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-12 rounded-lg shadow-lg flex items-center gap-2 transform transition-all hover:-translate-y-1 active:translate-y-0"
              >
                  <span className="material-icons-outlined">save_alt</span>
                  登 録
              </button>
          </div>
        </div>
      </div>

      <SlipPreviewModal 
        isOpen={isPreviewOpen} 
        onClose={() => setIsPreviewOpen(false)} 
        data={formData}
        onUpdate={setFormData}
      />
    </>
  );
};

export default InquiryDetail;

export enum ChannelType {
  PHONE = 'Phone',
  LINE = 'LINE',
  EMAIL = 'Email',
  FORM = 'Web Form'
}

export enum InquiryStatus {
  NEW = '新規',
  IN_PROGRESS = '対応中',
  DONE = '完了'
}

export enum ImageSize {
  SIZE_1K = '1K',
  SIZE_2K = '2K',
  SIZE_4K = '4K'
}

export interface VehicleInfo {
  make: string;
  model: string;
  year: string;
  mileage: string;
  color: string;
  inspectionDate?: string;
  chassisNumber?: string;
  plateStatus?: 'あり' | 'なし' | '外し済み';
  registrationNumber?: string;
  conditionNotes?: string;
}

export interface CustomerInfo {
  id: string;
  name: string;
  kana: string;
  phone: string;
  email: string;
  address?: string;
  preferredContact?: string;
  repName?: string; // 担当者名
  contactPhone?: string; // 連絡先
}

export interface SlipData {
  receptionName?: string; // 受付
  salesRep?: string; // 営業担当
  stockNumber?: string; // 入庫番号
  stockDate?: string; // 入庫日
  pickupRep?: string; // 引取り担当
  receptionDate?: string; // 受付日
  orderDate?: string; // 受注日
  scheduledDate?: string; // 予定日
  pickupMethod?: string; // 引き取り方法
  pickupLocation?: string; // 引取場所
  contactTiming?: string[]; // 送信開始時間, 店舗手続後引取などのフラグ
}

export interface Inquiry {
  id: string;
  customer: CustomerInfo;
  vehicle?: VehicleInfo;
  slip?: SlipData;
  channel: ChannelType;
  subject: string;
  content: string; // Full content
  lastMessage: string; // Summary for list
  timestamp: string;
  status: InquiryStatus;
  adminNotes?: string;
  handoverNote?: string; // 社内引き継ぎ用の一言コメント
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

