const Dashboard: React.FC = () => {
  // Calculate KPIs
  const totalInquiries = MOCK_INQUIRIES.length;
  const doneInquiries = MOCK_INQUIRIES.filter(i => i.status === InquiryStatus.DONE).length;
  const conversionRate = totalInquiries > 0 ? ((doneInquiries / totalInquiries) * 100).toFixed(1) : '0.0';

  // Calculate Channel Breakdown
  const channelStats = Object.values(ChannelType).map(channel => {
    const channelInquiries = MOCK_INQUIRIES.filter(i => i.channel === channel);
    const count = channelInquiries.length;
    const done = channelInquiries.filter(i => i.status === InquiryStatus.DONE).length;
    const rate = count > 0 ? ((done / count) * 100).toFixed(0) : '0';

    // Icon mapping
    let icon = 'help';
    let color = 'text-slate-500';
    if(channel === ChannelType.LINE) { icon = 'chat'; color = 'text-green-500'; }
    if(channel === ChannelType.PHONE) { icon = 'phone'; color = 'text-blue-500'; }
    if(channel === ChannelType.EMAIL) { icon = 'mail'; color = 'text-orange-500'; }
    if(channel === ChannelType.FORM) { icon = 'web'; color = 'text-purple-500'; }

    return { channel, count, rate, icon, color };
  });

  return (
    <div className="space-y-8">
      {/* Top Section: Critical KPIs */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* KPI Cards */}
        <div className="lg:col-span-1 space-y-6">
           <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex items-center justify-between">
              <div>
                 <p className="text-sm font-bold text-slate-500 mb-1">今月の問い合わせ総数</p>
                 <h3 className="text-4xl font-extrabold text-slate-800">{totalInquiries}<span className="text-lg font-medium text-slate-400 ml-2">件</span></h3>
              </div>
              <div className="p-4 bg-brand-50 rounded-full text-brand-600">
                 <span className="material-icons-outlined text-3xl">contact_phone</span>
              </div>
           </div>

           <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex items-center justify-between">
              <div>
                 <p className="text-sm font-bold text-slate-500 mb-1">全体成約率</p>
                 <h3 className="text-4xl font-extrabold text-slate-800">{conversionRate}<span className="text-lg font-medium text-slate-400 ml-2">%</span></h3>
              </div>
              <div className="p-4 bg-green-50 rounded-full text-green-600">
                 <span className="material-icons-outlined text-3xl">verified</span>
              </div>
           </div>
        </div>

        {/* Channel Breakdown Table */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
           <div className="px-6 py-4 border-b border-slate-100 bg-slate-50">
              <h3 className="font-bold text-slate-700 flex items-center gap-2">
                 <span className="material-icons-outlined">pie_chart</span>
                 媒体別パフォーマンス
