           </div>
           <table className="w-full text-left">
              <thead className="bg-slate-50 text-xs text-slate-500 uppercase">
                 <tr>
                    <th className="px-6 py-3 font-semibold">媒体</th>
                    <th className="px-6 py-3 font-semibold text-right">問い合わせ数</th>
                    <th className="px-6 py-3 font-semibold text-right">成約率</th>
                    <th className="px-6 py-3 font-semibold w-1/3">達成度</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                 {channelStats.map((stat) => (
                    <tr key={stat.channel} className="hover:bg-slate-50">
                       <td className="px-6 py-4 flex items-center gap-3">
                          <span className={`material-icons-outlined ${stat.color}`}>{stat.icon}</span>
                          <span className="font-bold text-slate-700">{stat.channel}</span>
                       </td>
                       <td className="px-6 py-4 text-right font-bold text-slate-800">{stat.count}件</td>
                       <td className="px-6 py-4 text-right font-bold text-slate-800">{stat.rate}%</td>
                       <td className="px-6 py-4 align-middle">
                          <div className="w-full bg-slate-200 rounded-full h-2">
                             <div 
                                className={`h-2 rounded-full ${parseInt(stat.rate) > 50 ? 'bg-green-500' : 'bg-brand-500'}`} 
                                style={{ width: `${stat.rate}%` }}
                             ></div>
                          </div>
                       </td>
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>
      </div>

      {/* Main Action Area: Inquiry List */}
      <div>
         <InquiryList />
      </div>
    </div>
  );
};

