                 <p className="text-sm font-bold text-slate-500 mb-1">今月の問い合わせ総数</p>
                 <h3 className="text-4xl font-extrabold text-slate-800">{totalInquiries}<span className="text-lg font-medium text-slate-400 ml-2">件</span></h3>
              </div>
              <div className="p-4 bg-brand-50 rounded-full text-brand-600">
                 <span className="material-icons-outlined text-3xl">contact_phone</span>
              </div>
           </div>

           <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex items-center justify-between">
              <div>
                 <p className="text-sm font-bold text-slate-500 mb-1">成約率 (CLOSED/ALL)</p>
                 <h3 className="text-4xl font-extrabold text-slate-800">{conversionRate}<span className="text-lg font-medium text-slate-400 ml-2">%</span></h3>
              </div>
              <div className="p-4 bg-green-50 rounded-full text-green-600">
                 <span className="material-icons-outlined text-3xl">verified</span>
              </div>
           </div>
        </div>

        {/* Channel Breakdown Table */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
           <div className="px-6 py-4 border-b border-slate-100 bg-slate-50">
              <h3 className="font-bold text-slate-700 flex items-center gap-2">
                 <span className="material-icons-outlined">pie_chart</span>
                 媒体別パフォーマンス
              </h3>
           </div>
           <table className="w-full text-left">
              <thead className="bg-slate-50 text-xs text-slate-500 uppercase">
                 <tr>
                    <th className="px-6 py-3 font-semibold">媒体</th>
                    <th className="px-6 py-3 font-semibold text-right">問い合わせ数</th>
                    <th className="px-6 py-3 font-semibold text-right">成約率</th>
                    <th className="px-6 py-3 font-semibold w-1/3">達成度</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                 {channelStats.map((stat) => (
                    <tr key={stat.channel} className="hover:bg-slate-50">
                       <td className="px-6 py-4 flex items-center gap-3">
                          <span className={`material-icons-outlined ${stat.color}`}>{stat.icon}</span>
                          <span className="font-bold text-slate-700">{stat.channel}</span>
                       </td>
                       <td className="px-6 py-4 text-right font-bold text-slate-800">{stat.count}件</td>
                       <td className="px-6 py-4 text-right font-bold text-slate-800">{stat.rate}%</td>
                       <td className="px-6 py-4 align-middle">
                          <div className="w-full bg-slate-200 rounded-full h-2">
                             <div 
                                className={`h-2 rounded-full ${parseInt(stat.rate) > 50 ? 'bg-green-500' : 'bg-brand-500'}`} 
                                style={{ width: `${stat.rate}%` }}
                             ></div>
                          </div>
                       </td>
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>
      </div>

      {/* Main Action Area: Inquiry List */}
      <div>
         <InquiryList />
      </div>
    </div>
  );
