import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { ImageSize } from '../types';

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

// 1. AI Powered Chatbot using gemini-3-pro-preview
export const createChatSession = (): Chat => {
  const ai = getAiClient();
  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: "You are a helpful assistant for 'Ishigami Vehicle' staff. You help draft responses to customers, summarize inquiries, and provide advice on vehicle buyouts. Be professional, polite, and concise in Japanese.",
    },
  });
};

export const sendMessageStream = async (chat: Chat, message: string) => {
  return chat.sendMessageStream({ message });
};

// 2. AI Text Refinement for Customer Communication
export const refineMessage = async (draft: string, type: 'SMS' | 'EMAIL'): Promise<string> => {
  const ai = getAiClient();
  const prompt = `
    あなたは自動車販売買取店「石上車両」のスタッフです。
    以下の「下書き」をもとに、お客様へ送るメッセージを清書してください。

    条件:
    - 送信手段: ${type}
    - ${type === 'SMS' ? 'SMSなので、簡潔に、短めの文章にしてください（1通に収まる程度）。' : 'メールなので、件名は含めず、ビジネスとして丁寧な挨拶と本文を作成してください。'}
    - 丁寧語を使用してください。
    - プレースホルダー（[お客様名]など）は使わず、文脈から判断できる内容は自然に補完してください。

    下書き:
    ${draft}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || draft;
  } catch (e) {
    console.error("Text refinement failed", e);
    return draft;
  }
};

// 3. Marketing Image Generation
export const generateMarketingImage = async (prompt: string, size: ImageSize): Promise<string | null> => {
  const ai = getAiClient();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: size
        }
      }
    });

    if (response.candidates && response.candidates[0].content && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const base64EncodeString = part.inlineData.data;
          // Return as data URL
          return `data:${part.inlineData.mimeType};base64,${base64EncodeString}`;
        }
      }
    }
    return null;
  } catch (e) {
    console.error("Image generation failed", e);
    return null;
  }
};

// 4. Vehicle Inspection Certificate OCR (AI Extraction)
export const parseVehicleInspectionCertificate = async (base64Image: string): Promise<any> => {
  const ai = getAiClient();

  // Clean base64 string if it contains data URI prefix
  const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg|webp);base64,/, "");

  const prompt = `
    この画像は日本の車検証（自動車検査証）です。
    画像から以下の情報を読み取り、JSON形式のみを出力してください。
    読み取れない項目は null にしてください。

    JSON Schema:
    {
      "make": "メーカー名 (例: トヨタ)",
      "model": "車名 (例: プリウス)",
      "year": "初度登録年 (例: 令和3年)",
      "chassisNumber": "車台番号",
      "registrationNumber": "自動車登録番号",
      "ownerName": "所有者の氏名または名称",
      "color": "備考欄などに記載があれば色、なければ推測しない",
      "mileage": "走行距離計表示値があれば"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash', // Flash is fast and good at OCR
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: cleanBase64 } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json"
      }
    });

    const text = response.text;
    if (text) {
      return JSON.parse(text);
    }
    return null;
  } catch (e) {
    console.error("Vehicle OCR failed", e);
    throw e;
  }
};

