                {/* 1. Customer Card */}
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div className="px-6 py-4 border-b border-slate-100 flex items-center gap-2 bg-slate-50">
                        <span className="material-icons-outlined text-brand-600">person</span>
                        <h3 className="font-bold text-slate-800">顧客情報</h3>
                    </div>
                    <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                         <div className="space-y-1">
                             <label className="text-xs font-bold text-slate-500">お名前</label>
                             <input 
                                type="text" 
                                value={formData.customer.name}
                                onChange={(e) => updateCustomer('name', e.target.value)}
                                className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500 font-bold"
                             />
                         </div>
                         <div className="space-y-1">
                             <label className="text-xs font-bold text-slate-500">連絡先 (TEL)</label>
                             <input 
                                type="text" 
                                value={formData.customer.phone}
                                onChange={(e) => updateCustomer('phone', e.target.value)}
                                className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                             />
                         </div>
                         <div className="md:col-span-2 space-y-1">
                             <label className="text-xs font-bold text-slate-500">住所</label>
                             <input 
                                type="text" 
                                value={formData.customer.address || ''}
                                onChange={(e) => updateCustomer('address', e.target.value)}
                                className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                                placeholder="例: 札幌市..."
                             />
                         </div>
                    </div>
                </div>

                {/* 2. Vehicle Card */}
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden relative">
                    {/* OCR Loading Overlay */}
                    {isOcrProcessing && (
                        <div className="absolute inset-0 bg-white/80 z-20 flex flex-col items-center justify-center">
                            <span className="w-10 h-10 border-4 border-brand-500 border-t-transparent rounded-full animate-spin mb-3"></span>
                            <span className="font-bold text-brand-700 animate-pulse">AIが車検証を読み取っています...</span>
                            <span className="text-xs text-slate-500 mt-1">Gemini 2.5 Flash</span>
                        </div>
                    )}

                    <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50">
                        <div className="flex items-center gap-2">
                            <span className="material-icons-outlined text-brand-600">directions_car</span>
                            <h3 className="font-bold text-slate-800">車両情報</h3>
                        </div>
                        <div>
                            <button 
                                onClick={() => ocrInputRef.current?.click()}
                                className="text-xs bg-gradient-to-r from-brand-600 to-purple-600 text-white font-bold py-1.5 px-3 rounded-lg flex items-center gap-1 shadow hover:shadow-md transition-all"
                            >
                                <span className="material-icons-outlined text-sm">document_scanner</span>
                                車検証から自動入力 (AI)
                            </button>
                            <input 
                                type="file" 
                                ref={ocrInputRef}
                                onChange={handleOcrFileChange}
                                className="hidden"
                                accept="image/*"
                            />
                        </div>
                    </div>
                    <div className="p-6 space-y-6">
                         <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                            <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500">車種名</label>
                                <input 
                                    type="text" 
                                    value={formData.vehicle?.model || ''}
                                    onChange={(e) => updateVehicle('model', e.target.value)}
                                    className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500 font-bold"
                                />
                            </div>
                            <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500">年式</label>
                                <input 
                                    type="text" 
                                    value={formData.vehicle?.year || ''}
                                    onChange={(e) => updateVehicle('year', e.target.value)}
                                    className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                                />
                            </div>
                             <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500">走行距離</label>
                                <input 
                                    type="text" 
                                    value={formData.vehicle?.mileage || ''}
                                    onChange={(e) => updateVehicle('mileage', e.target.value)}
                                    className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                                />
                            </div>
                             <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500">車体色</label>
                                <input 
                                    type="text" 
                                    value={formData.vehicle?.color || ''}
                                    onChange={(e) => updateVehicle('color', e.target.value)}
                                    className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                                />
                            </div>
                             <div className="md:col-span-2 space-y-1">
                                <label className="text-xs font-bold text-slate-500">車台番号</label>
                                <input 
                                    type="text" 
                                    value={formData.vehicle?.chassisNumber || ''}
                                    onChange={(e) => updateVehicle('chassisNumber', e.target.value)}
                                    className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500 font-mono uppercase"
                                />
                            </div>
                         </div>

                         <div className="space-y-1">
                             <label className="text-xs font-bold text-slate-500">車両状態・査定メモ</label>
                             <textarea 
                                rows={3}
                                value={formData.vehicle?.conditionNotes || ''}
                                onChange={(e) => updateVehicle('conditionNotes', e.target.value)}
                                className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                                placeholder="傷、凹み、エンジンの状態など..."
                             />
                         </div>

                         {/* Image Gallery */}
                         <div className="border-t border-slate-100 pt-6">
                            <ImageGallery 
                                images={formData.vehicle?.images || []}
                                onImagesChange={updateImages}
                            />
                         </div>
                    </div>
                </div>

                 {/* 3. Slip/Logistics Card */}
                 <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div className="px-6 py-4 border-b border-slate-100 flex items-center gap-2 bg-slate-50">
                        <span className="material-icons-outlined text-brand-600">local_shipping</span>
                        <h3 className="font-bold text-slate-800">伝票・業務情報</h3>
                    </div>
                    <div className="p-6 grid grid-cols-2 md:grid-cols-4 gap-6">
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-500">営業担当</label>
                            <input 
                                type="text"
                                value={formData.slip?.salesRep || ''}
                                onChange={(e) => updateSlip('salesRep', e.target.value)}
                                className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                            />
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-500">引取予定日</label>
                            <input 
                                type="date"
                                value={formData.slip?.scheduledDate || ''}
                                onChange={(e) => updateSlip('scheduledDate', e.target.value)}
                                className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                            />
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-500">入庫番号</label>
                            <input 
                                type="text"
                                value={formData.slip?.stockNumber || ''}
                                onChange={(e) => updateSlip('stockNumber', e.target.value)}
                                className="w-full border-slate-300 rounded-lg focus:ring-brand-500 focus:border-brand-500"
                            />
                        </div>
                    </div>
                </div>

            </div>

            {/* RIGHT COLUMN: Communication & Notes */}
            <div className="lg:col-span-1 space-y-6">

                {/* Handover Note */}
                <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4 shadow-sm">
                   <div className="flex items-center gap-2 mb-2 text-yellow-800">
                      <span className="material-icons-outlined">sticky_note_2</span>
                      <h3 className="font-bold text-sm">社内申し送り・備考</h3>
                   </div>
                   <textarea 
                      value={formData.handoverNote || ''}
                      onChange={(e) => setFormData({...formData, handoverNote: e.target.value})}
                      placeholder="次の担当者へのメモ..."
                      className="w-full bg-white border-yellow-300 rounded-lg text-sm p-3 focus:ring-2 focus:ring-yellow-400 focus:border-transparent min-h-[100px]"
                   />
                </div>

                {/* Communication Panel */}
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div className="px-4 py-3 border-b border-slate-100 bg-slate-50">
                        <h3 className="font-bold text-slate-800 text-sm">メッセージ送信</h3>
                    </div>
                    <div className="p-4 space-y-4">
                        <div className="flex gap-2">
                             <button 
                                onClick={() => setMessageType('SMS')}
                                className={`flex-1 py-1.5 rounded text-xs font-bold border transition-colors ${messageType === 'SMS' ? 'bg-brand-50 border-brand-200 text-brand-700' : 'bg-white border-slate-200 text-slate-500'}`}
                             >SMS</button>
                             <button 
                                onClick={() => setMessageType('EMAIL')}
                                className={`flex-1 py-1.5 rounded text-xs font-bold border transition-colors ${messageType === 'EMAIL' ? 'bg-orange-50 border-orange-200 text-orange-700' : 'bg-white border-slate-200 text-slate-500'}`}
                             >Email</button>
                        </div>
                        <div className="relative">
                            <textarea 
                                value={draftMessage}
                                onChange={(e) => setDraftMessage(e.target.value)}
                                className="w-full border-slate-300 rounded-lg text-sm p-3 min-h-[120px]"
                                placeholder="メッセージを入力..."
                            />
                            {isRefining && (
                                <div className="absolute inset-0 bg-white/70 flex items-center justify-center">
                                    <span className="text-brand-600 text-xs font-bold animate-pulse">AI推敲中...</span>
                                </div>
                            )}
                        </div>
                        <div className="flex gap-2 justify-end">
                            <button 
                                onClick={handleAiRefine}
                                disabled={!draftMessage || isRefining}
                                className="text-purple-600 text-xs font-bold flex items-center gap-1 hover:bg-purple-50 px-2 py-1 rounded"
                            >
                                <span className="material-icons-outlined text-sm">auto_awesome</span> AI推敲
                            </button>
                            <button 
                                onClick={() => {alert('送信しました'); setDraftMessage('');}}
                                className="bg-brand-600 hover:bg-brand-700 text-white text-xs font-bold py-2 px-4 rounded shadow"
                            >
                                送信
                            </button>
                        </div>
                    </div>
                </div>

                {/* History Timeline */}
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div className="px-4 py-3 border-b border-slate-100 bg-slate-50">
                        <h3 className="font-bold text-slate-800 text-sm">対応履歴</h3>
                    </div>
                    <div className="max-h-80 overflow-y-auto p-4 space-y-4">
                        {MOCK_HISTORY.map((item) => (
                            <div key={item.id} className="flex gap-3 items-start text-sm">
                                <div className={`mt-1 w-2 h-2 rounded-full flex-shrink-0 ${item.agent === 'お客様' ? 'bg-slate-400' : 'bg-brand-500'}`} />
                                <div>
                                    <div className="flex items-center gap-2 mb-0.5">
                                        <span className="font-bold text-slate-700 text-xs">{item.agent}</span>
                                        <span className="text-[10px] text-slate-400">{item.date}</span>
                                    </div>
                                    <p className="text-slate-600 bg-slate-50 p-2 rounded-lg text-xs leading-relaxed border border-slate-100">
                                        {item.content}
                                    </p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

            </div>
        </div>

      </div>

      <Suspense fallback={
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
            <div className="bg-white p-4 rounded-lg flex items-center gap-3">
                <span className="w-5 h-5 border-2 border-brand-500 border-t-transparent rounded-full animate-spin"></span>
                <span className="text-sm font-bold text-slate-700">帳票システム起動中...</span>
            </div>
        </div>
      }>
        {isPreviewOpen && (
            <SlipPreviewModal 
                isOpen={isPreviewOpen} 
                onClose={() => setIsPreviewOpen(false)} 
                data={formData}
                onUpdate={setFormData}
            />
        )}
      </Suspense>
    </>
  );
};

export default InquiryDetail;
